import React, { useState } from 'react';
import { View, Text, Button } from 'react-native';
import * as Purchases from '@react-native-purchases/core';

const PaymentModule = () => {
  const [purchaseStatus, setPurchaseStatus] = useState('');

  const handleInAppPurchase = async () => {
    try {
      await Purchases.purchaseProduct('product_id');
      setPurchaseStatus('Purchase successful!');
    } catch (error) {
      setPurchaseStatus(`Error: ${error.message}`);
    }
  };

  const handleDigitalWalletTransaction = async () => {
    try {
      await Purchases.makePaymentRequest({
        amount: 10.99,
        currencyCode: 'USD',
        paymentMethod: 'apple_pay', // or 'google_pay'
      });
      setPurchaseStatus('Transaction successful!');
    } catch (error) {
      setPurchaseStatus(`Error: ${error.message}`);
    }
  };

  return (
    <View>
      <Text>{purchaseStatus}</Text>
      <Button title="In-App Purchase" onPress={handleInAppPurchase} />
      <Button title="Digital Wallet Transaction" onPress={handleDigitalWalletTransaction} />
    </View>
  );
};

export default PaymentModule;